mapper.select:
SELECT b.book_id, b.book_title, b.author_name, b.publisher, b.publish_date, b.book_price, b.stock_status, b.book_summary, b.cover_image, b.category_id, b.isbn, b.book_stock, b.created_at, b.updated_at, IFNULL(SUM(oi.book_quantity), 0) AS sales_count, -- 판매 수량 IFNULL(AVG(r.review_score), 0) AS average_rating, -- 평점 평균 COUNT(r.review_id) AS review_count -- 리뷰 수 FROM book b LEFT JOIN orderitem oi ON b.book_id = oi.book_id LEFT JOIN review r ON b.book_id = r.book_id
AND (b.book_title LIKE CONCAT('%', #{search}, '%') OR b.author_name LIKE CONCAT('%', #{search}, '%'))
AND b.category_id = #{category_id}
GROUP BY b.book_id
ORDER BY sales_count DESC ORDER BY b.created_at DESC ORDER BY review_count DESC ORDER BY average_rating DESC ORDER BY b.book_id DESC
LIMIT #{pageStart}, #{perPageNum}

SELECT COUNT(*) FROM book
AND (book_title LIKE CONCAT('%', #{search}, '%') OR author_name LIKE CONCAT('%', #{search}, '%'))
AND category_id = #{category_id}
